        <div class="ctrl-btn empty"></div>
        <div class="ctrl-btn" data-dir="left">◀</div>
        <div class="ctrl-btn" data-dir="down">▼</div>
        <div class="ctrl-btn" data-dir="right">▶</div>
    </div>
</div>

<script>
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
const scoreEl = document.getElementById('score');
const highScoreEl = document.getElementById('highScore');

const GRID_SIZE = 25;
const CELL_SIZE = canvas.width / GRID_SIZE;
const INITIAL_SPEED = 150;
const MIN_SPEED = 60;

let snake, direction, nextDirection, food, specialFood, score, highScore, gameLoop, gameState;
let particles = [];
let specialFoodTimer = 0;
let animationFrame = 0;

highScore = parseInt(localStorage.getItem('snakeHighScore')) || 0;
highScoreEl.textContent = highScore;

function init() {
    const mid = Math.floor(GRID_SIZE / 2);
    snake = [
        { x: mid, y: mid },
        { x: mid - 1, y: mid },
        { x: mid - 2, y: mid },
    ];
    direction = { x: 1, y: 0 };
    nextDirection = { x: 1, y: 0 };
    score = 0;
    scoreEl.textContent = score;
    food = null;
    specialFood = null;
    specialFoodTimer = 0;
    particles = [];
    spawnFood();
    gameState = 'ready';
}

function spawnFood() {
    let pos;
    do {
        pos = {
            x: Math.floor(Math.random() * GRID_SIZE),
            y: Math.floor(Math.random() * GRID_SIZE)
        };
    } while (isOccupied(pos));
    food = pos;
    food.pulse = 0;
}

function spawnSpecialFood() {
    if (specialFood) return;
    let pos;
    do {
        pos = {
            x: Math.floor(Math.random() * GRID_SIZE),
            y: Math.floor(Math.random() * GRID_SIZE)
        };
    } while (isOccupied(pos) || (food && pos.x === food.x && pos.y === food.y));
    specialFood = pos;
    specialFood.life = 200;
    specialFood.pulse = 0;
}

function isOccupied(pos) {
    return snake.some(seg => seg.x === pos.x && seg.y === pos.y);
}

function createParticles(x, y, color, count) {
    for (let i = 0; i < count; i++) {
        particles.push({
            x: x * CELL_SIZE + CELL_SIZE / 2,
            y: y * CELL_SIZE + CELL_SIZE / 2,
            vx: (Math.random() - 0.5) * 8,
            vy: (Math.random() - 0.5) * 8,
            life: 1,
            decay: 0.02 + Math.random() * 0.03,
            color: color,
            size: 2 + Math.random() * 4
        });
    }
}

function updateParticles() {
    for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.x += p.vx;
        p.y += p.vy;
        p.vx *= 0.96;
        p.vy *= 0.96;
        p.life -= p.decay;
        if (p.life <= 0) particles.splice(i, 1);
    }
}

function drawParticles() {
    particles.forEach(p => {
        ctx.save();
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    });
}

function getSpeed() {
    return Math.max(MIN_SPEED, INITIAL_SPEED - score * 2);
}

function update() {
    if (gameState !== 'playing') return;

    direction = { ...nextDirection };

    const head = {
        x: snake[0].x + direction.x,
        y: snake[0].y + direction.y
    };

    // Wall collision
    if (head.x < 0 || head.x >= GRID_SIZE || head.y < 0 || head.y >= GRID_SIZE) {
        gameOver();
        return;
    }

    // Self collision
    if (snake.some(seg => seg.x === head.x && seg.y === head.y)) {
        gameOver();
        return;
    }

    snake.unshift(head);

    let ate = false;

    // Check food
    if (food && head.x === food.x && head.y === food.y) {
        score += 10;
        scoreEl.textContent = score;
        createParticles(food.x, food.y, '#ff6b6b', 15);
        spawnFood();
        ate = true;

        // Chance to spawn special food
        if (Math.random() < 0.3 && !specialFood) {
            spawnSpecialFood();
        }
    }

    // Check special food
    if (specialFood && head.x === specialFood.x && head.y === specialFood.y) {
        score += 50;
        scoreEl.textContent = score;
        createParticles(specialFood.x, specialFood.y, '#ffd700', 25);
        specialFood = null;
        ate = true;
        // Add extra segment
        snake.push({ ...snake[snake.length - 1] });
    }

    if (!ate) {
        snake.pop();
    }

    // Update special food timer
    if (specialFood) {
        specialFood.life--;
        if (specialFood.life <= 0) {
            createParticles(specialFood.x, specialFood.y, '#666', 8);
            specialFood = null;
        }
    }

    // Random special food spawn
    specialFoodTimer++;
    if (specialFoodTimer > 100 && !specialFood && Math.random() < 0.01) {
        spawnSpecialFood();
        specialFoodTimer = 0;
    }

    // Restart loop with potentially new speed
    clearInterval(gameLoop);
    gameLoop = setInterval(update, getSpeed());
}

function gameOver() {
    gameState = 'dead';
    clearInterval(gameLoop);

    // Explosion particles for each snake segment
    snake.forEach((seg, i) => {
        setTimeout(() => {
            createParticles(seg.x, seg.y, '#00d4ff', 5);
        }, i * 30);
    });

    if (score > highScore) {
        highScore = score;
        highScoreEl.textContent = highScore;
        localStorage.setItem('snakeHighScore', highScore);
    }
}

function drawGrid() {
    ctx.fillStyle = '#0a1628';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
    ctx.lineWidth = 0.5;
    for (let i = 0; i <= GRID_SIZE; i++) {
        ctx.beginPath();
        ctx.moveTo(i * CELL_SIZE, 0);
        ctx.lineTo(i * CELL_SIZE, canvas.height);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0, i * CELL_SIZE);
        ctx.lineTo(canvas.width, i * CELL_SIZE);
        ctx.stroke();
    }
}

function drawSnake() {
    snake.forEach((seg, i) => {
        const progress = i / snake.length;
        const r = Math.floor(0 + progress * 0);
        const g = Math.floor(212 - progress * 100);
        const b = Math.floor(255 - progress * 100);

        const x = seg.x * CELL_SIZE;
        const y = seg.y * CELL_SIZE;
        const padding = 1;
        const size = CELL_SIZE - padding * 2;

        // Glow effect for head
        if (i === 0) {
            ctx.save();
            ctx.shadowColor = '#00d4ff';
            ctx.shadowBlur = 15;
            ctx.fillStyle = '#00d4ff';
            ctx.beginPath();
            ctx.roundRect(x + padding, y + padding, size, size, 6);
            ctx.fill();
            ctx.restore();

            // Eyes
            const eyeSize = 3;
            ctx.fillStyle = '#0a1628';
            if (direction.x === 1) {
                ctx.beginPath();
                ctx.arc(x + size * 0.75, y + size * 0.3, eyeSize, 0, Math.PI * 2);
                ctx.fill();
                ctx.beginPath();
                ctx.arc(x + size * 0.75, y + size * 0.7, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            } else if (direction.x === -1) {
                ctx.beginPath();
                ctx.arc(x + size * 0.25, y + size * 0.3, eyeSize, 0, Math.PI * 2);
                ctx.fill();
                ctx.beginPath();
                ctx.arc(x + size * 0.25, y + size * 0.7, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            } else if (direction.y === -1) {
                ctx.beginPath();
                ctx.arc(x + size * 0.3, y + size * 0.25, eyeSize, 0, Math.PI * 2);
                ctx.fill();
                ctx.beginPath();
                ctx.arc(x + size * 0.7, y + size * 0.25, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            } else {
                ctx.beginPath();
                ctx.arc(x + size * 0.3, y + size * 0.75, eyeSize, 0, Math.PI * 2);
                ctx.fill();
                ctx.beginPath();
                ctx.arc(x + size * 0.7, y + size * 0.75, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            }
        } else {
            ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
            ctx.beginPath();
            ctx.roundRect(x + padding + 1, y + padding + 1, size - 2, size - 2, 4);
            ctx.fill();
        }
    });
}

function drawFood() {
    if (!food) return;
    animationFrame++;
    const pulse = Math.sin(animationFrame * 0.1) * 0.15 + 0.85;

    const x = food.x * CELL_SIZE + CELL_SIZE / 2;
    const y = food.y * CELL_SIZE + CELL_SIZE / 2;
    const radius = (CELL_SIZE / 2 - 3) * pulse;

    // Glow
    ctx.save();
    ctx.shadowColor = '#ff6b6b';
    ctx.shadowBlur = 15;

    // Apple body
    const gradient = ctx.createRadialGradient(x - 2, y - 2, 1, x, y, radius);
    gradient.addColorStop(0, '#ff8a8a');
    gradient.addColorStop(1, '#ff4444');
    ctx.fillStyle = gradient;
    ctx.beginPath();
    ctx.arc(x, y, radius, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Shine
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.beginPath();
    ctx.arc(x - radius * 0.3, y - radius * 0.3, radius * 0.25, 0, Math.PI * 2);
    ctx.fill();
}

function drawSpecialFood() {
    if (!specialFood) return;
    const pulse = Math.sin(animationFrame * 0.15) * 0.2 + 0.8;
    const x = specialFood.x * CELL_SIZE + CELL_SIZE / 2;
    const y = specialFood.y * CELL_SIZE + CELL_SIZE / 2;
    const radius = (CELL_SIZE / 2 - 2) * pulse;

    // Blinking when about to disappear
    if (specialFood.life < 60 && Math.floor(animationFrame / 5) % 2 === 0) return;

    ctx.save();
    ctx.shadowColor = '#ffd700';
    ctx.shadowBlur = 20;

    // Star shape
    const gradient = ctx.createRadialGradient(x, y, 1, x, y, radius);
    gradient.addColorStop(0, '#fff7a0');
    gradient.addColorStop(1, '#ffd700');
    ctx.fillStyle = gradient;

    ctx.beginPath();
    const spikes = 5;
    const outerRadius = radius;
    const innerRadius = radius * 0.5;
    for (let i = 0; i < spikes * 2; i++) {
        const r = i % 2 === 0 ? outerRadius : innerRadius;
        const angle = (i * Math.PI / spikes) - Math.PI / 2;
        if (i === 0) ctx.moveTo(x + r * Math.cos(angle), y + r * Math.sin(angle));
        else ctx.lineTo(x + r * Math.cos(angle), y + r * Math.sin(angle));
    }
    ctx.closePath();
    ctx.fill();
    ctx.restore();
}

function drawOverlay(text, subtext) {
    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = '#00d4ff';
    ctx.font = 'bold 48px "Segoe UI", sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(text, canvas.width / 2, canvas.height / 2 - 30);

    ctx.fillStyle = '#aaa';
    ctx.font = '20px "Segoe UI", sans-serif';
    ctx.fillText(subtext, canvas.width / 2, canvas.height / 2 + 25);
}

function render() {
    drawGrid();
    drawFood();
    drawSpecialFood();
    drawSnake();
    drawParticles();
    updateParticles();

    if (gameState === 'ready') {
        drawOverlay('🐍 贪食蛇', '按任意方向键开始游戏');
    } else if (gameState === 'paused') {
        drawOverlay('⏸ 暂停', '按空格键继续');
    } else if (gameState === 'dead') {
        drawOverlay(`💀 游戏结束 - ${score} 分`, score >= highScore && score > 0 ? '🎉 新纪录！按 R 重新开始' : '按 R 重新开始');
    }

    requestAnimationFrame(render);
}

function startGame() {
    if (gameState !== 'ready') return;
    gameState = 'playing';
    gameLoop = setInterval(update, getSpeed());
}

function setDirection(dx, dy) {
    // Prevent 180-degree turns
    if (direction.x === -dx && direction.y === -dy) return;
    if (direction.x === dx && direction.y === dy) return;
    nextDirection = { x: dx, y: dy };
}

// Keyboard controls
document.addEventListener('keydown', (e) => {
    const key = e.key.toLowerCase();

    if (gameState === 'ready') {
        if (['arrowup', 'arrowdown', 'arrowleft', 'arrowright', 'w', 'a', 's', 'd'].includes(key)) {
            if (key === 'arrowup' || key === 'w') nextDirection = { x: 0, y: -1 };
            else if (key === 'arrowdown' || key === 's') nextDirection = { x: 0, y: 1 };
            else if (key === 'arrowleft' || key === 'a') nextDirection = { x: -1, y: 0 };
            else if (key === 'arrowright' || key === 'd') nextDirection = { x: 1, y: 0 };
            direction = { ...nextDirection };
            startGame();
            e.preventDefault();
            return;
        }
    }

    if (gameState === 'playing') {
        switch (key) {
            case 'arrowup': case 'w': setDirection(0, -1); e.preventDefault(); break;
            case 'arrowdown': case 's': setDirection(0, 1); e.preventDefault(); break;
            case 'arrowleft': case 'a': setDirection(-1, 0); e.preventDefault(); break;
            case 'arrowright': case 'd': setDirection(1, 0); e.preventDefault(); break;
        }
    }

    if (key === ' ') {
        e.preventDefault();
        if (gameState === 'playing') {
            gameState = 'paused';
            clearInterval(gameLoop);
        } else if (gameState === 'paused') {
            gameState = 'playing';
            gameLoop = setInterval(update, getSpeed());
        }
    }

    if (key === 'r') {
        clearInterval(gameLoop);
        init();
    }
});

// Mobile controls
document.querySelectorAll('.ctrl-btn[data-dir]').forEach(btn => {
    btn.addEventListener('touchstart', (e) => {
        e.preventDefault();
        const dir = btn.dataset.dir;
        if (gameState === 'ready') {
            if (dir === 'up') nextDirection = { x: 0, y: -1 };
            else if (dir === 'down') nextDirection = { x: 0, y: 1 };
            else if (dir === 'left') nextDirection = { x: -1, y: 0 };
            else if (dir === 'right') nextDirection = { x: 1, y: 0 };
            direction = { ...nextDirection };
            startGame();
            return;
        }
        if (gameState === 'dead') {
            clearInterval(gameLoop);
            init();
            return;
        }
        if (dir === 'up') setDirection(0, -1);
        else if (dir === 'down') setDirection(0, 1);
        else if (dir === 'left') setDirection(-1, 0);
        else if (dir === 'right') setDirection(1, 0);
    });
});

// Swipe controls
let touchStartX = 0, touchStartY = 0;
canvas.addEventListener('touchstart', (e) => {
    touchStartX = e.touches[0].clientX;
    touchStartY = e.touches[0].clientY;
    e.preventDefault();

    if (gameState === 'dead') {
        clearInterval(gameLoop);
        init();
    }
});
canvas.addEventListener('touchmove', (e) => e.preventDefault(), { passive: false });
canvas.addEventListener('touchend', (e) => {
    const dx = e.changedTouches[0].clientX - touchStartX;
    const dy = e.changedTouches[0].clientY - touchStartY;
    const absDx = Math.abs(dx);
    const absDy = Math.abs(dy);

    if (Math.max(absDx, absDy) < 20) return;

    let dir;
    if (absDx > absDy) {
        dir = dx > 0 ? { x: 1, y: 0 } : { x: -1, y: 0 };
    } else {
        dir = dy > 0 ? { x: 0, y: 1 } : { x: 0, y: -1 };
    }

    if (gameState === 'ready') {
        nextDirection = dir;
        direction = { ...dir };
        startGame();
        return;
    }
    if (gameState === 'playing') {
        setDirection(dir.x, dir.y);
    }
});

// Polyfill roundRect if needed
if (!CanvasRenderingContext2D.prototype.roundRect) {
    CanvasRenderingContext2D.prototype.roundRect = function(x, y, w, h, r) {
        if (typeof r === 'number') r = [r];
        const rad = r[0] || 0;
        this.moveTo(x + rad, y);
        this.lineTo(x + w - rad, y);
        this.quadraticCurveTo(x + w, y, x + w, y + rad);
        this.lineTo(x + w, y + h - rad);
        this.quadraticCurveTo(x + w, y + h, x + w - rad, y + h);
        this.lineTo(x + rad, y + h);
        this.quadraticCurveTo(x, y + h, x, y + h - rad);
        this.lineTo(x, y + rad);
        this.quadraticCurveTo(x, y, x + rad, y);
        this.closePath();
        return this;
    };
}

init();
render();
</script>
</body>
</html>
